function HomeServices() {
  const homeServices = [
    {
      title: "Cleaning Help",
      description:
        "Connect with community members who can help with cleaning, organizing, and basic home care.",
    },
    {
      title: "Furniture Moving",
      description:
        "Find helpers who can support families with moving furniture and carrying heavy home items.",
    },
    {
      title: "Cooking Support",
      description:
        "Get assistance with simple meal preparation for families, elderly people, or people in need.",
    },
    {
      title: "Small Home Tasks",
      description:
        "Request help with everyday tasks such as arranging rooms or basic home preparation.",
    },
  ];

  return (
    <section className="page-section">
      <div className="page-header">
        <h1>Home Services</h1>

        <p>
          Home Services helps community members find support for daily household
          tasks that can be difficult to manage alone.
        </p>
      </div>

      <section className="cards">
        {homeServices.map((service, index) => (
          <div className="card" key={index}>
            <h3>{service.title}</h3>
            <p>{service.description}</p>
          </div>
        ))}
      </section>
    </section>
  );
}

export default HomeServices;
